package main

import (
	"context"
	"fmt"
	"net"
	"testing"
	"time"

	"github.com/stretchr/testify/require"
	"go.flipt.io/flipt/internal/server/auth"
	storageauth "go.flipt.io/flipt/internal/storage/auth"
	"go.flipt.io/flipt/internal/storage/auth/memory"
	authrpc "go.flipt.io/flipt/rpc/flipt/auth"
	"go.uber.org/zap/zaptest"
	"google.golang.org/grpc"
	"google.golang.org/grpc/credentials/insecure"
	"google.golang.org/grpc/metadata"
	"google.golang.org/protobuf/types/known/emptypb"
)

// TestRegression tests the authentication limitations described in the issue:
// 1. Cookie-based tokens are not extracted from HTTP cookies
// 2. There is no mechanism to skip authentication for specific servers
func TestRegression(t *testing.T) {
	// Test 1: Cookie-based token extraction failure
	t.Run("Cookie-based tokens are not extracted", func(t *testing.T) {
		testCookieTokenExtraction(t)
	})

	// Test 2: No server skip mechanism for authentication
	t.Run("No mechanism to skip authentication for servers", func(t *testing.T) {
		testServerAuthenticationSkipMechanism(t)
	})
}

// testCookieTokenExtraction demonstrates that valid tokens in cookies are not recognized
func testCookieTokenExtraction(t *testing.T) {
	// Create an authenticator and token
	authenticator := memory.NewStore()
	clientToken, storedAuth, err := authenticator.CreateAuthentication(
		context.TODO(),
		&storageauth.CreateAuthenticationRequest{Method: authrpc.Method_METHOD_TOKEN},
	)
	require.NoError(t, err)
	require.NotNil(t, storedAuth)

	logger := zaptest.NewLogger(t)
	interceptor := auth.UnaryInterceptor(logger, authenticator)

	// Test Case 1: Token in Authorization header works
	t.Run("Token in Authorization header is accepted", func(t *testing.T) {
		ctx := context.Background()
		md := metadata.MD{
			"authorization": []string{"Bearer " + clientToken},
		}
		ctx = metadata.NewIncomingContext(ctx, md)

		var retrievedAuth *authrpc.Authentication
		handler := func(ctx context.Context, req interface{}) (interface{}, error) {
			retrievedAuth = auth.GetAuthenticationFrom(ctx)
			return nil, nil
		}

		resp, err := interceptor(ctx, nil, nil, handler)
		require.NoError(t, err, "Authorization header should be accepted")
		require.NotNil(t, retrievedAuth, "Authentication should be extracted from context")
		require.Equal(t, storedAuth.Id, retrievedAuth.Id)
		_ = resp
	})

	// Test Case 2: Token in cookie is NOT recognized (BUG DEMONSTRATION)
	// This demonstrates the bug - valid tokens in cookies are rejected
	t.Run("Token in cookie is NOT extracted (BUG)", func(t *testing.T) {
		ctx := context.Background()
		// Simulating a cookie being passed via metadata
		// In real HTTP scenarios, cookies would come as metadata from grpc-gateway
		md := metadata.MD{
			"cookie": []string{"flipt_client_token=" + clientToken},
		}
		ctx = metadata.NewIncomingContext(ctx, md)

		var retrievedAuth *authrpc.Authentication
		handler := func(ctx context.Context, req interface{}) (interface{}, error) {
			retrievedAuth = auth.GetAuthenticationFrom(ctx)
			return nil, nil
		}

		_, err := interceptor(ctx, nil, nil, handler)
		// This SHOULD fail because the middleware doesn't check cookies
		require.Error(t, err, "Cookie-based tokens are not extracted - middleware only checks Authorization header")
		require.Nil(t, retrievedAuth, "Authentication should not be extracted from cookie")
	})

	// Test Case 3: Token in metadata cookie key (alternative representation)
	t.Run("Token in alternate cookie representation is NOT extracted", func(t *testing.T) {
		ctx := context.Background()
		md := metadata.MD{
			"flipt_client_token": []string{clientToken},
		}
		ctx = metadata.NewIncomingContext(ctx, md)

		var retrievedAuth *authrpc.Authentication
		handler := func(ctx context.Context, req interface{}) (interface{}, error) {
			retrievedAuth = auth.GetAuthenticationFrom(ctx)
			return nil, nil
		}

		_, err := interceptor(ctx, nil, nil, handler)
		require.Error(t, err, "Tokens in custom cookie metadata keys are not recognized")
		require.Nil(t, retrievedAuth)
	})
}

// testServerAuthenticationSkipMechanism demonstrates there's no way to skip auth for specific servers
func testServerAuthenticationSkipMechanism(t *testing.T) {
	// Create an authenticator
	authenticator := memory.NewStore()
	logger := zaptest.NewLogger(t)

	// Start a test gRPC server with authentication middleware
	lis, err := net.Listen("tcp", "127.0.0.1:0")
	require.NoError(t, err)
	defer lis.Close()

	// Create the gRPC server WITH authentication interceptor
	// This demonstrates that ALL servers must go through authentication
	interceptor := auth.UnaryInterceptor(logger, authenticator)
	grpcServer := grpc.NewServer(
		grpc.UnaryInterceptor(interceptor),
	)
	defer grpcServer.Stop()

	// Register a test service
	authrpc.RegisterAuthenticationServiceServer(grpcServer, auth.NewServer(logger, authenticator))

	go grpcServer.Serve(lis)
	time.Sleep(100 * time.Millisecond)

	// Connect to the server
	conn, err := grpc.DialContext(
		context.Background(),
		lis.Addr().String(),
		grpc.WithTransportCredentials(insecure.NewCredentials()),
	)
	require.NoError(t, err)
	defer conn.Close()

	client := authrpc.NewAuthenticationServiceClient(conn)

	// Test Case 1: Unauthenticated request fails
	t.Run("Request without authentication fails", func(t *testing.T) {
		_, err := client.GetAuthenticationSelf(context.Background(), &emptypb.Empty{})
		require.Error(t, err, "Unauthenticated request should fail")
	})

	// Test Case 2: There is no configuration option to skip authentication for this service
	// This test demonstrates the limitation - we can't prove absence directly,
	// but we show that the auth server itself must also be authenticated
	t.Run("Auth service itself requires authentication (no skip mechanism)", func(t *testing.T) {
		// Even the auth service endpoints require authentication
		// There's no way to mark the AuthenticationService as exempt from authentication
		// This is a design flaw - users setting up Flipt can't even create their first token
		// without already having a valid token to authenticate the CreateToken request

		// Demonstrate that ListAuthentications requires authentication
		_, err := client.ListAuthentications(context.Background(), &authrpc.ListAuthenticationsRequest{})
		require.Error(t, err, "List authentications should require authentication")

		// And there's no way to disable this check for the token creation service
		// which means you can't create the initial bootstrap token without already having one
	})

	// Test Case 3: Verify the auth middleware is indeed enforcing on all services
	t.Run("Auth middleware is applied to all registered services", func(t *testing.T) {
		// The interceptor chain is applied globally at line 486 in main.go:
		// if cfg.Authentication.Required {
		//    interceptors = append(interceptors, auth.UnaryInterceptor(logger, authenticationStore))
		// }
		//
		// This demonstrates that there is NO mechanism to selectively disable
		// authentication for specific services or servers.
		// All servers created with the same ServerOptions will have authentication enforced.

		// Create another server - it will also have the same interceptor
		lis2, err := net.Listen("tcp", "127.0.0.1:0")
		require.NoError(t, err)
		defer lis2.Close()

		// Same interceptor applied
		grpcServer2 := grpc.NewServer(
			grpc.UnaryInterceptor(interceptor),
		)
		defer grpcServer2.Stop()

		authrpc.RegisterAuthenticationServiceServer(grpcServer2, auth.NewServer(logger, authenticator))
		go grpcServer2.Serve(lis2)
		time.Sleep(100 * time.Millisecond)

		conn2, err := grpc.DialContext(
			context.Background(),
			lis2.Addr().String(),
			grpc.WithTransportCredentials(insecure.NewCredentials()),
		)
		require.NoError(t, err)
		defer conn2.Close()

		client2 := authrpc.NewAuthenticationServiceClient(conn2)

		// This server also requires authentication - no way to skip
		_, err = client2.GetAuthenticationSelf(context.Background(), &emptypb.Empty{})
		require.Error(t, err, "Second server also requires authentication - no skip mechanism exists")
	})

	// Test Case 4: Document the configuration design flaw
	t.Run("Bootstrap token creation requires existing authentication (chicken-and-egg problem)", func(t *testing.T) {
		// In main.go:560-572, the token server is registered and attempts bootstrap:
		// if cfg.Authentication.Methods.Token.Enabled {
		//    clientToken, err := authstorage.Bootstrap(ctx, authenticationStore)
		//    ...
		//    tokenServer := authtoken.NewServer(logger, authenticationStore)
		//    authrpc.RegisterAuthenticationMethodTokenServiceServer(grpcServer, tokenServer)
		// }
		//
		// However, the CreateToken RPC is protected by the same auth interceptor.
		// Users cannot call CreateToken to create their first token because
		// the endpoint itself requires authentication.
		//
		// There should be a mechanism to:
		// 1. Mark certain services as "unauthenticated"
		// 2. Or provide a bootstrap endpoint that bypasses authentication
		// 3. Or allow per-service authentication configuration

		// This is a limitation of the current architecture - we can verify
		// that the auth middleware is globally applied with no per-service control
		require.True(t, true, "Bootstrap token creation has dependency on authentication - design flaw documented")
	})
}

// BenchmarkAuthMiddleware measures the performance impact of the auth middleware
// This helps understand the overhead of the authentication system
func BenchmarkAuthMiddleware(b *testing.B) {
	authenticator := memory.NewStore()
	clientToken, _, err := authenticator.CreateAuthentication(
		context.TODO(),
		&storageauth.CreateAuthenticationRequest{Method: authrpc.Method_METHOD_TOKEN},
	)
	if err != nil {
		b.Fatalf("failed to create authentication: %v", err)
	}

	logger := zaptest.NewLogger(b)
	interceptor := auth.UnaryInterceptor(logger, authenticator)

	ctx := context.Background()
	md := metadata.MD{
		"authorization": []string{"Bearer " + clientToken},
	}
	ctx = metadata.NewIncomingContext(ctx, md)

	handler := func(ctx context.Context, req interface{}) (interface{}, error) {
		return nil, nil
